async (params, browser) => {
  // Open the tweet
  await browser.open(`${params.tweet_url}`)

  // Wait for page content
  await browser.waitForSelector('article[data-testid=\'tweet\']', 15000)

  // Let page settle
  await browser.wait(1000)

  // Wait for bookmark button
  await browser.waitForSelector('[data-testid$=\'bookmark\']', 10000)

  // Bookmark the tweet
  const result = await browser.evaluate(`const bookmarkBtn = document.querySelector('[data-testid$="bookmark"]'); const unbookmarkBtn = document.querySelector('[data-testid$="removeBookmark"]'); if (unbookmarkBtn) return { already_bookmarked: true, message: 'Tweet is already bookmarked' }; if (bookmarkBtn) { bookmarkBtn.click(); return { success: true, message: 'Tweet bookmarked' }; } return { success: false, message: 'Bookmark button not found' }`)

  return result
}
